function test_is_empty() {
    $exchange = new \ccxt\async\Exchange(array(
        'id' => 'sampleexchange',
    ));
    assert($exchange->is_empty(null) === true, 'undefined should be empty');
    assert($exchange->is_empty(null) === true, 'null should be empty');
    assert($exchange->is_empty(array()) === true, 'empty object should be empty');
    assert($exchange->is_empty([]) === true, 'empty array should be empty');
    assert($exchange->is_empty(array(
    'foo' => 1,
)) === false, 'non-empty object should not be empty');
    assert($exchange->is_empty([1, 2]) === false, 'non-empty array should not be empty');
    // below are scalars, so they are not checked.
    // @ts-expect-error
    assert($exchange->is_empty('') === false, 'empty string should return false');
    // @ts-expect-error
    assert($exchange->is_empty(0) === false, 'zero should return false');
    // @ts-expect-error
    assert($exchange->is_empty(false) === false, 'false should return false');
    // @ts-expect-error
    assert($exchange->is_empty('non-empty string') === false, 'non-empty string should not be empty');
}
